String callWithRetry(java.util.concurrent.Callable<String> action) {
    long backoffMs = 100;
    int maxAttempts = 4;

    for (int attempt = 1; attempt <= maxAttempts; attempt++) {
        try {
            return action.call();
        } catch (Exception e) {
            if (attempt == maxAttempts) {
                return "FAILED";
            }
            try {
                Thread.sleep(backoffMs);
            } catch (InterruptedException ie) {
                Thread.currentThread().interrupt();
                return "INTERRUPTED";
            }
            backoffMs *= 2;
        }
    }
    return "FAILED";
}

